<?php
declare(strict_types=1);namespace Vigilancia\Tests\Unit;use PHPUnit\Framework\TestCase;use Vigilancia\Validation\Validator;final class ValidatorTest extends TestCase{public function testDetectaCamposObligatorios():void{$this->assertArrayHasKey('name',Validator::required([],['name']));}public function testAceptaFalseComoValorBooleanoPresente():void{$this->assertSame([],Validator::required(['allowed'=>false],['allowed']));}public function testValidaContrasenaRobusta():void{$this->assertTrue(Validator::strongPassword('ClaveSegura#2026'));$this->assertFalse(Validator::strongPassword('debil'));}public function testValidaCorreo():void{$this->assertTrue(Validator::email('admin@example.com'));$this->assertFalse(Validator::email('correo-invalido'));}}
